/// Standalone function to calculate total file size from a vector of sizes.
/// Uses regular addition (which panics on overflow in debug mode).
pub fn calculate_total_file_size(file_sizes: &[u64]) -> Result<u64, BatchDownloadError> {
    if file_sizes.is_empty() {
        return Err(BatchDownloadError::EmptyFileList);
    }

    let mut total: u64 = 0;
    for &size in file_sizes {
        total = total.checked_add(size).ok_or(BatchDownloadError::Overflow)?;
    }
    Ok(total)
}

/// Standalone function using wrapping_add for performance-critical paths.
pub fn calculate_total_file_size_wrapping(file_sizes: &[u64]) -> Result<u64, BatchDownloadError> {
    if file_sizes.is_empty() {
        return Err(BatchDownloadError::EmptyFileList);
    }

    let total = file_sizes
        .iter()
        .fold(0u64, |acc, &size| acc.wrapping_add(size));
    Ok(total)
}

